  ('climate_type', 'Paramo Bajo', 'Paramo Bajo', '{"altitude_range": "3200-3700", "source_row": 6, "source_sheet": "Caracteristicas", "temperature_range": "12>T°>7"}'::jsonb, 6, TRUE),
  ('climate_type', 'Paramo Alto', 'Paramo Alto', '{"altitude_range": "3701-4200", "source_row": 7, "source_sheet": "Caracteristicas", "temperature_range": "T<7"}'::jsonb, 7, TRUE),
  ('agrologic_class', 'I', 'I', '{"description": "Tierras de alta calidad. Aptas para agricultura intensiva, ganadería y bosques.", "limitations": "Casi nulas. Requieren prácticas sencillas de manejo de suelos.", "mechanization": "Total. Sin restricciones para cualquier equipo.", "slope": "0% - 1%", "slope_description": "(Plano)", "source_row": 2, "source_sheet": "Caracteristicas"}'::jsonb, 2, TRUE),
  ('agrologic_class', 'II', 'II', '{"description": "Tierras muy buenas. Aptas para agricultura, ganadería y sistemas forestales.", "limitations": "Ligeras. Riesgo leve de erosión o drenaje algo lento.", "mechanization": "Alta. Mecanización fácil de todas las labores.", "slope": "1% - 3%", "slope_description": "(Ligeramente inclinado)", "source_row": 3, "source_sheet": "Caracteristicas"}'::jsonb, 3, TRUE),
  ('agrologic_class', 'III', 'III', '{"description": "Tierras buenas. Aptas para cultivos permanentes y transitorios con manejo.", "limitations": "Moderadas. Requieren rotación de cultivos y control de escorrentía.", "mechanization": "Media. Requiere equipos con potencia o prácticas de contorno.", "slope": "3% - 7%", "slope_description": "(Moderadamente inclinado)", "source_row": 4, "source_sheet": "Caracteristicas"}'::jsonb, 4, TRUE),
  ('agrologic_class', 'IV', 'IV', '{"description": "Tierras de uso limitado. Aptas para cultivos permanentes (frutales) o pastos.", "limitations": "Severas. Alta susceptibilidad a la erosión si se remueve la cobertura.", "mechanization": "Limitada. Solo equipos livianos o especializados; alto riesgo de vuelco.", "slope": "7% - 12%", "slope_description": "(Fuertemente inclinado)", "source_row": 5, "source_sheet": "Caracteristicas"}'::jsonb, 5, TRUE),
  ('agrologic_class', 'V', 'V', '{"description": "Tierras de pastoreo/bosque. No aptas para arado por factores físicos.", "limitations": "Muy severas por pedregosidad o inundación frecuente.", "mechanization": "Nula o muy baja. Generalmente el suelo no soporta el peso de máquinas.", "slope": "0% - 1%", "slope_description": "(Plano/Cóncavo)", "source_row": 6, "source_sheet": "Caracteristicas"}'::jsonb, 6, TRUE),
  ('agrologic_class', 'VI', 'VI', '{"description": "Tierras de vocación ganadera. Aptas para pastoreo y silvicultura.", "limitations": "Muy severas. El suelo suele ser delgado y el relieve dificulta el manejo.", "mechanization": "No mecanizable. Labores principalmente manuales o tracción animal.", "slope": "12% - 25", "slope_description": "% (Moderadamente quebrado)", "source_row": 7, "source_sheet": "Caracteristicas"}'::jsonb, 7, TRUE),
  ('agrologic_class', 'VII', 'VII', '{"description": "Tierras forestales. Aptas para conservación o extracción regulada.", "limitations": "Extremas. El uso agropecuario causa degradación irreversible.", "mechanization": "Nula. Prohibido el uso de maquinaria por riesgo de erosión severa.", "slope": "25% - 50", "slope_description": "% (Quebrado a escarpado)", "source_row": 8, "source_sheet": "Caracteristicas"}'::jsonb, 8, TRUE),
  ('agrologic_class', 'VIII', 'VIII', '{"description": "Tierras de conservación. Áreas protegidas, páramos y zonas de recarga.", "limitations": "Absolutas para producción. Solo para vida silvestre y ecoturismo.", "mechanization": "Nula. Solo acceso peatonal o para monitoreo ambiental.", "slope": "> 50%", "slope_description": "montañoso / Escarpado", "source_row": 9, "source_sheet": "Caracteristicas"}'::jsonb, 9, TRUE),
